request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?model
  ?modelName
  ?idLike
WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }

  {
    ?model tai:normalizedId ?idLike .
    FILTER(CONTAINS(STR(?idLike), "1f1b01e0a85340689b6df314b32bb4b6"))
  }
  UNION
  {
    ?model tai:originalId ?idLike .
    FILTER(CONTAINS(STR(?idLike), "1f1b01e0a85340689b6df314b32bb4b6"))
  }
  UNION
  {
    ?model bbo:id ?idLike .
    FILTER(CONTAINS(STR(?idLike), "1f1b01e0a85340689b6df314b32bb4b6"))
  }
  UNION
  {
    FILTER(CONTAINS(STR(?model), "1f1b01e0a85340689b6df314b32bb4b6"))
    BIND(STR("uri_contains") AS ?idLike)
  }
}
LIMIT 25
